android.extraProguardRules:
# R-SEC-4: ProGuard rules complementares (Onda R, 2026-05-21)
# Bibliotecas com consumerProguardFiles ja contribuem regras proprias via AAR:
# react-native (core), react-native-reanimated, react-native-worklets,
# react-native-health-connect, expo-modules-core, react-native-svg,
# expo-notifications, expo-location. As linhas abaixo cobrem casos
# defensivos (reflexao runtime, OkHttp, classes do app, JS bundle).

# App package — preserva entry points
-keep class com.ouroboros.mobile.** { *; }

# Hermes engine (interop JS<->native)
-keep class com.facebook.hermes.unicode.** { *; }
-keep class com.facebook.jni.** { *; }

# OkHttp/OkIO (fetch interno do RN)
-dontwarn okhttp3.**
-dontwarn okio.**
-dontwarn javax.annotation.**
-keepnames class okhttp3.internal.publicsuffix.PublicSuffixDatabase

# Health Connect SDK (records via reflexao por nome de classe)
-keep class androidx.health.connect.client.** { *; }
-keep class androidx.health.platform.client.** { *; }

# Reanimated 4 + Worklets (turbomodule + worklets runtime)
-keep class com.swmansion.reanimated.** { *; }
-keep class com.swmansion.worklets.** { *; }

# gluestack-ui / nativewind / moti — usam reflexao via React props
-keepclassmembers,includedescriptorclasses class * {
  @com.facebook.react.uimanager.annotations.ReactProp <methods>;
}

# SecureStore / Biometric — chaves Android Keystore via reflexao
-keep class androidx.biometric.** { *; }
-keep class androidx.security.crypto.** { *; }

# Stack traces legiveis em crashes producao (linha original do .kt/.java)
-keepattributes SourceFile,LineNumberTable
-renamesourcefileattribute SourceFile
